/* src/logger.c */
#include <stdio.h>
#include <string.h>

/* Receives message from UDS diagnostic session */
void log_message(const char *msg) {
    /* line 28: CWE-134 format string - msg comes from network */
    printf(msg);
    /* Should be: printf("%s", msg); */
}

/* src/diag_handler.c */
#include <string.h>
extern void log_message(const char *msg);

void recv_diagnostic(int sock_fd) {
    char buf[512];
    int n = recv(sock_fd, buf, sizeof(buf) - 1, 0);
    if (n > 0) {
        buf[n] = '\0';
        log_message(buf);  /* network input flows to printf */
    }
}
